import com.rti.dds.type.builtin.KeyedString;
import com.rti.dds.type.builtin.StringDataReader;
import com.rti.dds.type.builtin.StringDataWriter;
import com.rti.dds.util.TypedOctets;

public class ModelInterface {
    private static final String TOPIC_NAME = "model_data_topic";
    private static final String MODEL_NAME = "valve_model";
    private StringDataReader dataReader;
    private StringDataWriter dataWriter;

    // 初始化数据读取器和数据写入器
    public void initialize() {
        String peer = "localhost";
