        DomainParticipantFactory factory = DomainParticipantFactory.get_instance();
        DomainParticipant participant = factory.create_participant(0, DomainParticipantFactory.PARTICIPANT_QOS_DEFAULT, null, StatusKind.STATUS_MASK_NONE);
        Topic topic = participant.create_topic(TOPIC_NAME, KeyedString.PARTICIPANT_MESSAGE_TYPE_NAME, DomainParticipant.TOPIC_QOS_DEFAULT, null, StatusKind.STATUS_MASK_NONE);

        Subscriber subscriber = participant.create_subscriber(DomainParticipant.SUBSCRIBER_QOS_DEFAULT, null, StatusKind.STATUS_MASK_NONE);
        dataReader = (StringDataReader) subscriber.create_datareader(topic, Subscriber.DATAREADER_QOS_DEFAULT, new CustomSubscriberListener(), StatusKind.STATUS_MASK_ALL);

        Publisher publisher = participant.create_publisher(DomainParticipant.PUBLISHER_QOS_DEFAULT, null, StatusKind.STATUS_MASK_NONE);
        dataWriter = (StringDataWriter) publisher.create_datawriter(topic, Publisher.DATAWRITER_QOS_DEFAULT, null, StatusKind.STATUS_MASK_NONE);

        participant.enable();
    }

    // 发布数据
    public void publishData(String modelName, Vector3 position, Quaternion rotation, Vector3 scale) {
        StringBuilder data = new StringBuilder();
        data.append("{");
        data.append("\"modelName\":\"").append(modelName).append("\",");
        data.append("\"position\":{\"x\":").append(position.x).append(",\"y\":").append(position.y).append(",\"z\":").append(position.z).append("},");
        data.append("\"rotation\":{\"x\":").append(rotation.x).append(",\"y\":").append(rotation.y).append(",\"z\":").append(rotation.z).append(",\"w\":").append(rotation.w).append("},");
        data.append("\"scale\":{\"x\":").append(scale.x).append(",\"y\":").append(scale.y).append(",\"z\":").append(scale.z).append("}");
        data.append("}");

        TypedOctets typedData = new TypedOctets(data.toString().getBytes());
        dataWriter.write(typedData, InstanceHandle_t.HANDLE_NIL);
    }

    // 关闭数据读取器和数据写入器
